"""Funciones de agregación para aprendizaje federado."""from __future__ import annotationsfrom typing import Anyimport numpy as npdef aggregate_client_states(    global_coef: np.ndarray,    global_intercept: np.ndarray,    client_states: list[dict[str, Any]],    server_lr: float = 0.3,) -> tuple[np.ndarray, np.ndarray]:    """    Agrega las actualizaciones locales de varios clientes.    Se calcula una media ponderada por número de muestras y después    se mezcla con el estado global anterior usando server_lr.    Parameters    ----------    global_coef : np.ndarray        Coeficientes actuales del modelo global.    global_intercept : np.ndarray        Interceptos actuales del modelo global.    client_states : list[dict[str, Any]]        Lista de estados locales de clientes. Cada estado debe contener:        - "coef_"        - "intercept_"        - "n_samples"    server_lr : float        Peso de la nueva actualización agregada frente al modelo global previo.    Returns    -------    tuple[np.ndarray, np.ndarray]        Nuevos coeficientes e interceptos del modelo global.    """    if not client_states:        return global_coef, global_intercept    total_samples = sum(state["n_samples"] for state in client_states)    if total_samples == 0:        return global_coef, global_intercept    avg_coef = np.zeros_like(global_coef, dtype=np.float64)    avg_intercept = np.zeros_like(global_intercept, dtype=np.float64)    for state in client_states:        weight = state["n_samples"] / total_samples        avg_coef += weight * state["coef_"]        avg_intercept += weight * state["intercept_"]    new_coef = (1.0 - server_lr) * global_coef + server_lr * avg_coef    new_intercept = (1.0 - server_lr) * global_intercept + server_lr * avg_intercept    return new_coef, new_intercept